arguments.file_text:
@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments - Dispatcher View</PageTitle>

<h1>Shipments</h1>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Filter by destination..."
           @bind="filterText" @bind:event="oninput" />
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">
                            @shipment.Status
                        </span>
                    </td>
                    <td>@shipment.ShippedDate.ToString("yyyy-MM-dd")</td>
                    <td>@(shipment.EstimatedDelivery?.ToString("yyyy-MM-dd") ?? "—")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@shipment.Status"
                                @onchange="(e) => UpdateStatus(shipment, e.Value?.ToString())">
                            <option value="Pending">Pending</option>
                            <option value="In Transit">In Transit</option>
                            <option value="Out for Delivery">Out for Delivery</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Delayed">Delayed</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s => string.IsNullOrEmpty(filterText)
            || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, string? newStatus)
    {
        if (string.IsNullOrEmpty(newStatus) || newStatus == shipment.Status)
            return;

        await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
        shipment.Status = newStatus;
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Delivered" => "bg-success",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-info",
        "Delayed" => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@searching">
                @(searching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedNumber</strong>.
    </div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment @shipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd>
                            <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">
                                @shipment.Status
                            </span>
                        </dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                <strong>@shipment.EstimatedDelivery.Value.ToString("MMMM dd, yyyy")</strong>
                                @{
                                    var daysLeft = (shipment.EstimatedDelivery.Value - DateTime.UtcNow).Days;
                                }
                                @if (shipment.Status != "Delivered")
                                {
                                    if (daysLeft > 0)
                                    {
                                        <span class="text-muted"> (@daysLeft day(s) remaining)</span>
                                    }
                                    else if (daysLeft == 0)
                                    {
                                        <span class="text-success"> (arriving today)</span>
                                    }
                                    else
                                    {
                                        <span class="text-danger"> (overdue)</span>
                                    }
                                }
                            }
                            else
                            {
                                <span class="text-muted">Not yet estimated</span>
                            }
                        </dd>
                    </dl>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool searched;
    private bool searching;

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        searching = true;
        searched = false;
        shipment = null;

        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        searchedNumber = trackingNumber.Trim();
        searched = true;
        searching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Delivered" => "bg-success",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-info",
        "Delayed" => "bg-danger",
        _ => "bg-secondary"
    };
}

